prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?org ?label ?orgId WHERE {
  ?org a bboExt:Organization .
  ?org tai:organizationId "67e70970f0404a7e87122700ad26d87b" .
  OPTIONAL { ?org rdfs:label ?label . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?modelName ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  ?org tai:organizationId "67e70970f0404a7e87122700ad26d87b" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
ORDER BY ?created

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT 
  ?modelName
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?participant) AS ?participantCount)
  (COUNT(DISTINCT ?gateway) AS ?gatewayCount)
  (COUNT(DISTINCT ?startEvent) AS ?startCount)
  (COUNT(DISTINCT ?endEvent) AS ?endCount)
WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  ?org tai:organizationId "67e70970f0404a7e87122700ad26d87b" .
  ?model bbo:name ?modelName .
  ?def a bboExt:Definitions .
  ?def tai:belongsTo ?model .
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?def .
  OPTIONAL {
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?participant a bboExt:Participant .
    ?participant tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?gateway tai:belongsTo ?choreo .
    FILTER EXISTS {
      { ?gateway a bboExt:ExclusiveGateway . }
      UNION { ?gateway a bboExt:ParallelGateway . }
      UNION { ?gateway a bboExt:EventBasedGateway . }
    }
  }
  OPTIONAL {
    ?startEvent a bboExt:StartEvent .
    ?startEvent tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?endEvent a bboExt:EndEvent .
    ?endEvent tai:belongsTo ?choreo .
  }
}
GROUP BY ?modelName
ORDER BY ?modelName
